SELECT location_id, COUNT(report_id) AS report_count, MAX(report_date) AS last_report_date
FROM location_reports
GROUP BY location_id;

SELECT location_id, access_type, COUNT(*) AS access_count
FROM location_access
GROUP BY location_id, access_type;

SELECT location_id, value AS population
FROM location_metadata
WHERE key = 'population';

SELECT MAX(value) AS max_elevation
FROM location_metadata
WHERE key = 'elevation';

SELECT access_id, location_id, access_date
FROM location_access
WHERE access_type = 'view';

SELECT COUNT(*) AS total_edit_accesses
FROM location_access
WHERE access_type = 'edit';

SELECT report_type, report_date
FROM location_reports
WHERE report_type = 'trends';

SELECT report_date, report_type
FROM location_reports
ORDER BY report_date DESC;
